   721→export const parseCommand = (input: string): ShellCommand => {
   722→  const trimmed = input.trim();
   723→
   724→  // Check for AI command
   725→  if (trimmed.startsWith('/ai ') || trimmed === '/ai') {
   726→    return {
   727→      type: 'ai',
   728→      name: 'ai',
   729→      args: trimmed.slice(4).trim().split(/\s+/).filter(Boolean),
   730→      raw: trimmed,
   731→    };
   732→  }
   733→
   734→  // Check for builtin command (starts with /)
   735→  if (trimmed.startsWith('/')) {
   736→    const parts = trimmed.slice(1).split(/\s+/);
   737→    const name = parts[0]?.toLowerCase() || '';
   738→
   739→    if (BUILTIN_COMMANDS.has(name)) {
   740→      return {
   741→        type: 'builtin',
   742→        name,
   743→        args: parts.slice(1),
   744→        raw: trimmed,
   745→      };
   746→    }
   747→  }
   748→
   749→  // System command (npm, node, etc.)
   750→  const parts = trimmed.split(/\s+/);
   751→  return {
   752→    type: 'system',
   753→    name: parts[0] || '',
   754→    args: parts.slice(1),
