  1378→/**
  1379→ * Check if WebContainer is supported and enabled
  1380→ */
  1381→export const isWebContainerSupported = (): {
  1382→  supported: boolean;
  1383→  reason?: string
  1384→} => {
  1385→  if (!('SharedArrayBuffer' in window)) {
  1386→    return {
  1387→      supported: false,
  1388→      reason: 'SharedArrayBuffer not available (requires Cross-Origin Isolation)',
  1389→    };
  1390→  }
  1391→
  1392→  if (!crossOriginIsolated) {
  1393→    return {
  1394→      supported: false,
  1395→      reason: 'Cross-Origin Isolation not enabled (COEP/COOP headers required)',
  1396→    };
  1397→  }
  1398→
  1399→  return { supported: true };
