     1→/**
     2→ * Phantom Shell Service
     3→ *
     4→ * Handles command parsing, execution, and output routing.
     5→ * Integrates with WebContainer for actual command execution
     6→ * and AI providers for /ai commands.
     7→ */
     8→
     9→import { logger } from '../logger';
    10→import type { PhantomProject } from '../../stores/usePhantomShellStore';
    11→import type { WebContainerProcess } from '@webcontainer/api';
    12→import { getWebContainer, isWebContainerSupported } from './webContainerService';
    13→
    14→const log = logger.module('PhantomShell:ShellService');
    15→
    16→// ==================== TYPES ====================
    17→
    18→export interface CommandResult {
    19→  exitCode: number;
    20→  stdout: string;
    21→  stderr: string;
    22→}
    23→
    24→export interface ShellCommand {
    25→  type: 'builtin' | 'ai' | 'system';
    26→  name: string;
    27→  args: string[];
    28→  raw: string;
    29→}
    30→
    31→export interface ShellContext {
    32→  terminal: { clear: () => void; write: (data: string) => void } | null;
    33→  activeProjectId: string | null;
    34→  getHistory: () => { command: string; timestamp: string }[];
    35→  getProjects: () => { id: string; name: string; metadata: { framework?: string } }[];
    36→  createProject: (name: string) => string;
    37→}
    38→
    39→// Built-in commands that don't require WebContainer
    40→const BUILTIN_COMMANDS = new Set([
    41→  'help', 'clear', 'history', 'projects', 'new', 'open', 'close',
    42→  'export', 'import', 'theme', 'version', 'about',
    43→]);
    44→
    45→// ==================== COMMAND PARSER ====================
    46→
    47→export const parseCommand = (input: string): ShellCommand => {
    48→  const trimmed = input.trim();
    49→
    50→  // Check for AI command
    51→  if (trimmed.startsWith('/ai ') || trimmed === '/ai') {
    52→    return {
    53→      type: 'ai',
    54→      name: 'ai',
    55→      args: trimmed.slice(4).trim().split(/\s+/).filter(Boolean),
    56→      raw: trimmed,
    57→    };
    58→  }
    59→
    60→  // Check for builtin command (starts with /)
    61→  if (trimmed.startsWith('/')) {
    62→    const parts = trimmed.slice(1).split(/\s+/);
    63→    const name = parts[0]?.toLowerCase() || '';
    64→
    65→    if (BUILTIN_COMMANDS.has(name)) {
    66→      return {
    67→        type: 'builtin',
    68→        name,
    69→        args: parts.slice(1),
    70→        raw: trimmed,
    71→      };
    72→    }
    73→  }
    74→
    75→  // System command (npm, node, etc.)
    76→  const parts = trimmed.split(/\s+/);
    77→  return {
    78→    type: 'system',
    79→    name: parts[0] || '',
    80→    args: parts.slice(1),
    81→    raw: trimmed,
    82→  };
    83→};
    84→
    85→// ==================== BUILTIN COMMAND HANDLERS ====================
    86→
    87→export const builtinHandlers: Record<string, (args: string[], context: ShellContext) => string> = {
    88→  help: () => `
    89→\x1b[1;36mPhantom Shell Commands\x1b[0m
    90→
    91→\x1b[33mBuilt-in Commands:\x1b[0m
    92→  /help              Show this help message
    93→  /clear             Clear terminal screen
    94→  /history           Show command history
    95→  /version           Show version info
    96→  /about             About Phantom Shell
    97→
    98→\x1b[33mProject Commands:\x1b[0m
    99→  /projects          List all projects
   100→  /new <name>        Create new project
   101→  /open <name>       Open existing project
   102→  /close             Close current project
   103→  /export            Export project to .brain file
   104→
   105→\x1b[33mAI Commands:\x1b[0m
   106→  /ai <prompt>       Ask AI to help (e.g., /ai create a react app)
   107→
   108→\x1b[33mSystem Commands:\x1b[0m (requires WebContainer - Phase 2)
   109→  npm, node, npx     Standard Node.js commands
   110→  ls, cd, cat, etc.  File system commands
   111→`,
   112→
   113→  clear: (_args, context) => {
   114→    context.terminal?.clear();
   115→    return '';
   116→  },
   117→
   118→  history: (_args, context) => {
   119→    const history = context.getHistory();
   120→    if (history.length === 0) {
   121→      return '\x1b[90mNo command history\x1b[0m';
   122→    }
   123→    return history
   124→      .slice(-20)
   125→      .map((entry, i) => `\x1b[90m${i + 1}.\x1b[0m ${entry.command}`)
   126→      .join('\n');
   127→  },
   128→
   129→  version: () => {
   130→    const support = isWebContainerSupported();
   131→    const wcStatus = support.supported
   132→      ? '\x1b[32m✓ available\x1b[0m'
   133→      : `\x1b[31m✗ ${support.reason}\x1b[0m`;
   134→
   135→    return `
   136→\x1b[1;35mPhantom Shell\x1b[0m v1.0.0
   137→\x1b[90mNeuman Brain Dashboard\x1b[0m v2.0.0
   138→\x1b[90mWebContainer API\x1b[0m v1.5.1 ${wcStatus}
   139→\x1b[90mxterm.js\x1b[0m v5.5.0
   140→`;
   141→  },
   142→
   143→  projects: (_args, context) => {
   144→    const projects = context.getProjects();
   145→    if (projects.length === 0) {
   146→      return '\x1b[90mNo projects yet. Use \x1b[33m/new <name>\x1b[90m to create one.\x1b[0m';
   147→    }
   148→
   149→    return projects
   150→      .map(p => {
   151→        const active = context.activeProjectId === p.id ? '\x1b[32m● \x1b[0m' : '  ';
   152→        const framework = p.metadata.framework ? `\x1b[90m[${p.metadata.framework}]\x1b[0m` : '';
   153→        return `${active}\x1b[36m${p.name}\x1b[0m ${framework}`;
   154→      })
   155→      .join('\n');
   156→  },
   157→
   158→  new: (args, context) => {
   159→    const name = args.join(' ').trim();
   160→    if (!name) {
   161→      return '\x1b[31mError: Project name required\x1b[0m\nUsage: /new <project-name>';
   162→    }
   163→
   164→    // Validate name
   165→    if (!/^[a-zA-Z0-9_-]+$/.test(name)) {
   166→      return '\x1b[31mError: Invalid project name\x1b[0m\nUse only letters, numbers, hyphens, and underscores.';
   167→    }
