     1→/**
     2→ * AI Provider Router
     3→ * Routes messages to appropriate providers with automatic fallback support
     4→ * Handles provider failures, rate limits, and intelligent routing
     5→ */
     6→
     7→import type {
     8→  AIProvider,
     9→  AIModel,
    10→  AIMessageOptions,
    11→  AIResponse,
    12→  ProviderRouterConfig,
    13→} from './types';
    14→import { ProviderError, ProviderErrorType } from './types';
    15→import { openRouterProvider } from './openRouterProvider';
    16→import { groqProvider } from './groqProvider';
    17→import { huggingFaceProvider } from './huggingFaceProvider';
    18→import { mistralProvider } from './mistralProvider';
    19→import { geminiProvider } from './geminiProvider';
    20→import { openaiProvider } from './openaiProvider';
    21→import { logger } from '../logger';
    22→
    23→const log = logger.module('ProviderRouter');
    24→import { anthropicProvider } from './anthropicProvider';
    25→import { xaiProvider } from './xaiProvider';
    26→
    27→/**
    28→ * Fallback notification callback
    29→ */
    30→export type FallbackCallback = (
    31→  failedProvider: string,
    32→  failedModel: string,
    33→  nextProvider: string,
    34→  nextModel: string,
    35→  reason: string
    36→) => void;
    37→
    38→/**
    39→ * Provider registry
    40→ */
    41→const PROVIDERS: Record<string, AIProvider> = {
    42→  openrouter: openRouterProvider,
    43→  groq: groqProvider,
    44→  huggingface: huggingFaceProvider,
    45→  mistral: mistralProvider,
    46→  gemini: geminiProvider,
    47→  openai: openaiProvider,
    48→  anthropic: anthropicProvider,
    49→  xai: xaiProvider,
    50→};
    51→
    52→/**
    53→ * Default fallback order (best to worst)
    54→ */
    55→const DEFAULT_FALLBACK_ORDER = [
    56→  'openrouter', // Best flexibility
    57→  'groq', // Best speed
    58→  'huggingface', // Free fallback
    59→  'mistral', // European option
    60→  'gemini', // Google fallback
    61→];
    62→
    63→/**
    64→ * AI Provider Router
    65→ * Manages provider selection and automatic fallbacks
    66→ */
    67→export class AIProviderRouter {
    68→  private config: ProviderRouterConfig;
    69→  private onFallback?: FallbackCallback;
    70→
    71→  constructor(config: ProviderRouterConfig, onFallback?: FallbackCallback) {
    72→    this.config = config;
    73→    this.onFallback = onFallback;
    74→  }
    75→
    76→  /**
    77→   * Update router configuration
    78→   */
    79→  updateConfig(config: Partial<ProviderRouterConfig>): void {
    80→    this.config = { ...this.config, ...config };
    81→  }
    82→
    83→  /**
    84→   * Get provider by ID
    85→   */
    86→  getProvider(providerId: string): AIProvider | null {
    87→    return PROVIDERS[providerId] || null;
    88→  }
    89→
    90→  /**
    91→   * Get all providers
    92→   */
    93→  getAllProviders(): Record<string, AIProvider> {
    94→    return PROVIDERS;
    95→  }
    96→
    97→  /**
    98→   * Get configured providers (those with API keys)
    99→   */
   100→  getConfiguredProviders(): AIProvider[] {
   101→    return Object.values(PROVIDERS).filter((provider) => provider.isConfigured());
   102→  }
   103→
   104→  /**
   105→   * Get primary provider
   106→   */
   107→  getPrimaryProvider(): AIProvider | null {
   108→    return this.getProvider(this.config.primaryProvider);
   109→  }
   110→
   111→  /**
   112→   * Get fallback providers in order
   113→   */
   114→  getFallbackProviders(): AIProvider[] {
   115→    const fallbackOrder = this.config.fallbackOrder.length > 0
   116→      ? this.config.fallbackOrder
   117→      : DEFAULT_FALLBACK_ORDER;
   118→
   119→    return fallbackOrder
   120→      .filter((id) => id !== this.config.primaryProvider) // Exclude primary
   121→      .map((id) => this.getProvider(id))
   122→      .filter((provider): provider is AIProvider => provider !== null && provider.isConfigured());
   123→  }
   124→
   125→  /**
   126→   * Check if a provider error is retryable with fallback
   127→   */
   128→  private isRetryableError(error: ProviderError): boolean {
   129→    // Rate limits and network errors are retryable with different provider
   130→    return (
   131→      error.type === ProviderErrorType.RATE_LIMIT ||
   132→      error.type === ProviderErrorType.QUOTA_EXCEEDED ||
   133→      error.type === ProviderErrorType.NETWORK_ERROR ||
   134→      error.type === ProviderErrorType.TIMEOUT
   135→    );
   136→  }
   137→
   138→  /**
   139→   * Send message with automatic fallback
   140→   */
   141→  async sendMessage(options: AIMessageOptions): Promise<AIResponse> {
   142→    const primaryProvider = this.getPrimaryProvider();
   143→
   144→    if (!primaryProvider) {
   145→      throw new Error(
   146→        `Primary provider "${this.config.primaryProvider}" not found or not configured.`
   147→      );
   148→    }
   149→
   150→    // Try primary provider first
   151→    try {
   152→      const response = await primaryProvider.sendMessage(this.config.primaryModel, options);
   153→      return response;
   154→    } catch (error) {
   155→      // If fallback is disabled, throw immediately
   156→      if (!this.config.fallbackEnabled) {
   157→        throw error;
   158→      }
   159→
   160→      // Check if error is retryable
   161→      if (error instanceof ProviderError && this.isRetryableError(error)) {
   162→        log.warn('Provider failed with retryable error, attempting fallback', {
   163→          provider: error.provider,
   164→          message: error.message
   165→        });
   166→
   167→        // Try fallback providers
   168→        const fallbackProviders = this.getFallbackProviders();
   169→
   170→        for (const fallbackProvider of fallbackProviders) {
   171→          try {
   172→            // Get default model for fallback provider
   173→            const fallbackModel = fallbackProvider.getDefaultModel();
   174→
   175→            // Notify about fallback
   176→            if (this.config.notifyOnFallback && this.onFallback) {
   177→              this.onFallback(
   178→                this.config.primaryProvider,
   179→                this.config.primaryModel,
